3_real_world_example.code:
//  With Promises (.then chain)
function fetchUserOld() {
  fetch('/api/user')
    .then(res => res.json())
    .then(user => console.log('Old way:', user.name));
}

//  With async/await (Flat and readable)
async function fetchUserNew() {
  // Execution pauses here until fetch finishes. Call Stack is free!
  const res = await fetch('/api/user'); 

  // Resumes here. Execution pauses again until JSON parses.
  const user = await res.json();

  // Resumes here.
  console.log('New way:', user.name);
}

